"""PULSIFY — seed.py  |  Run after schema.sql to populate database"""
import os, json, urllib.request, urllib.error
from pathlib import Path
from datetime import datetime, timedelta

env = {}
for p in ["/workspaces/Pulsify/.env", ".env"]:
    if Path(p).exists():
        for line in Path(p).read_text().splitlines():
            if "=" in line and not line.startswith("#"):
                k, v = line.split("=", 1)
                env[k.strip()] = v.strip()
        break

URL = env.get("SUPABASE_URL", "https://cjzewfvtdayjgjdpdmln.supabase.co")
KEY = env.get("SUPABASE_SERVICE_KEY", "sb_secret_ZJa0UCrtdTUfFZT_p3zCfg_1m7F5QRf")

def ok(m): print(f"  OK   {m}")
def err(m): print(f"  ERR  {m}")
def days(n): return (datetime.now() + timedelta(days=n)).strftime("%Y-%m-%d")

def upsert(table, rows):
    all_keys = set()
    for r in rows: all_keys.update(r.keys())
    normalised = [{k: r.get(k) for k in all_keys} for r in rows]
    errors = []
    for i in range(0, len(normalised), 20):
        chunk = normalised[i:i+20]
        data = json.dumps(chunk).encode()
        req = urllib.request.Request(
            f"{URL}/rest/v1/{table}", data=data, method="POST",
            headers={"Content-Type":"application/json","apikey":KEY,
                     "Authorization":f"Bearer {KEY}","Prefer":"resolution=merge-duplicates,return=minimal"})
        try:
            with urllib.request.urlopen(req, timeout=30): pass
        except urllib.error.HTTPError as e:
            body = e.read().decode()
            errors.append(body[:100])
    if errors: err(f"{table}: {errors[0]}")
    else: ok(f"{table}: {len(rows)} rows upserted")

