print(f"\n{'='*52}")
print(f"  PULSIFY SEEDER")
print(f"  Target: {URL}")
print(f"{'='*52}\n")

upsert("events", EVENTS)
upsert("businesses", BUSINESSES)

# Insert ticket tiers
TIERS = []
for ev in EVENTS:
    if not ev.get("is_free") and ev.get("price_min"):
        TIERS.append({"event_id":ev["id"],"name":"General Admission","price":ev["price_min"],"capacity":300,"sold":0,"sort_order":1})
        if float(ev["price_min"]) < 300:
            TIERS.append({"event_id":ev["id"],"name":"VIP Experience","price":float(ev["price_min"])*2,"capacity":50,"sold":0,"sort_order":2})

req = urllib.request.Request(
    f"{URL}/rest/v1/ticket_tiers",
    data=json.dumps(TIERS).encode(), method="POST",
    headers={"Content-Type":"application/json","apikey":KEY,"Authorization":f"Bearer {KEY}","Prefer":"return=minimal"})
try:
    with urllib.request.urlopen(req, timeout=30): ok(f"ticket_tiers: {len(TIERS)} tiers inserted")
except urllib.error.HTTPError as e:
    body = e.read().decode()
    if "duplicate" in body or "23505" in body: ok("ticket_tiers: already exist (skipped)")
    else: err(f"ticket_tiers: {body[:80]}")

print(f"\n{'='*52}")
print(f"  SEED COMPLETE")
print(f"  {len(EVENTS)} events | {len(BUSINESSES)} businesses")
print(f"{'='*52}\n")
